INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '96350d3e-6468-48ac-841c-ffc0d9e6d6ca',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy's Hidden Data Profiler — Rapid Dataset Exploration Without Pandas$escape$,
  $escape$Most developers reach for pandas to profile data, but NumPy alone handles the heavy lifting when you need speed on raw arrays. Start with `np.isnan()` paired with `np.count_nonzero()` to map missing values per column instantly. For distribution insight, `np.percentile()` with a quartile array `[25, 50, 75]` gives you the spread without summary libraries. Combine `np.unique(return_counts=True)` to detect cardinality and spot categorical columns hiding in numeric arrays.

The real power move: `np.histogram()` returns bin edges and counts, letting you detect skew and outliers programmatically — compare the median from `np.median()` against the mean from `np.mean()`. A large divergence flags skew. For multi-column profiling, broadcast these ops across axis=0 on a 2D array to profile every feature in one vectorized pass. This avoids Python-level loops entirely, keeping profiling time sub-millisecond even on datasets with hundreds of thousands of rows.$escape$,
  $escape$import numpy as np

data = np.random.randn(10000, 5)
data[np.random.choice(10000, 500), 2] = np.nan  # inject missing values

# Per-column missing count
missing = np.count_nonzero(np.isnan(data), axis=0)
print("Missing per col:", missing)

# Distribution summary (ignoring NaNs)
print("Mean:", np.nanmean(data, axis=0))
print("Std:",  np.nanstd(data, axis=0))
print("Quartiles:\n", np.nanpercentile(data, [25, 50, 75], axis=0))

# Skew detection: mean vs median divergence
skew_signal = np.nanmean(data, axis=0) - np.nanmedian(data, axis=0)
print("Skew signal:", skew_signal)$escape$,
  $escape$python$escape$,
