INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '21328674-6b19-4e6c-b3e9-73bce9da8c2b',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy Statistical Testing — Bootstrapped Confidence Intervals Without SciPy$escape$,
  $escape$Most developers reach for scipy.stats for hypothesis testing, but NumPy alone handles bootstrap-based inference surprisingly well. The key insight: you don't need parametric assumptions when you can resample.

np.random.choice with replace=True is your bootstrap engine. Draw thousands of resampled datasets, compute your statistic on each, then use np.percentile to extract confidence intervals directly from the empirical distribution.

For a two-sample test, compute the mean difference on each bootstrap iteration and check what fraction of deltas cross zero — that's your p-value, no t-distribution required.

When this matters: small samples where normality assumptions break, metrics like medians or ratios where closed-form CIs don't exist, and A/B tests on skewed data (latency, revenue). NumPy's vectorized operations make 10k bootstrap iterations fast — reshape your samples into a (n_iterations, sample_size) matrix with np.random.choice and compute statistics along axis=1 in one shot.$escape$,
  $escape$import numpy as np

rng = np.random.default_rng(42)
data = rng.normal(loc=50, scale=10, size=200)

n_boot = 10_000
boot_indices = rng.integers(0, len(data), size=(n_boot, len(data)))
boot_samples = data[boot_indices]
boot_means = boot_samples.mean(axis=1)

ci_lower, ci_upper = np.percentile(boot_means, [2.5, 97.5])
observed_mean = data.mean()

# Two-tailed p-value: test if mean == 45
null_shifted = data - observed_mean + 45
null_boots = null_shifted[rng.integers(0, len(data), size=(n_boot, len(data)))]
p_value = np.mean(np.abs(null_boots.mean(axis=1) - 45) >= abs(observed_mean - 45))

print(f"Mean: {observed_mean:.2f}, 95% CI: [{ci_lower:.2f}, {ci_upper:.2f}], p={p_value:.4f}")$escape$,
  $escape$python$escape$,
